from pathlib import Path

import pytest
import yaml

from astar import a_star


FIXTURES_DIR = Path(__file__).parent / 'fixtures'


def load_fixture(path):
    '''Read a single YAML fixture into a plain dict.'''
    with open(path) as f:
        # safe_load sidesteps the 5.4+ default-loader change the fixtures pin
        # against; the fixtures are plain mappings/lists with no custom tags.
        return yaml.safe_load(f)


@pytest.fixture(params=sorted(FIXTURES_DIR.glob('*.yaml')),
                ids=lambda path: path.stem)
def case(request):
    return load_fixture(request.param)


def test_a_star_matches_fixture(case):
    heuristic_map = case['heuristic']

    def heuristic(node):
        return heuristic_map[node]

    path, length = a_star(case['graph'], case['start'], case['goal'],
                          heuristic)

    assert path == case['expected_path']
    assert length == case['expected_length']


def test_reported_length_matches_path_weight(case):
    if case['expected_path'] is None:
        pytest.skip('goal is unreachable, so there is no path to re-sum')

    graph = case['graph']
    heuristic_map = case['heuristic']

    def heuristic(node):
        return heuristic_map[node]

    path, length = a_star(graph, case['start'], case['goal'], heuristic)

    recomputed = sum(graph[path[i]][path[i + 1]]
                     for i in range(len(path) - 1))
    assert recomputed == length

